private void traverse(Node node) {
  if (!shouldVisit(node)) {
    return;
  }

  int visits = 0;
  do {
    Node c = node.getFirstChild();
    while (c != null) {
      Node next = c.getNext();
      traverse(c);
      c = next;
    }
    visit(node);
    visits++;
  } while (shouldRetraverse(node) && visits < 10);

  exitNode(node);
}
